mapper.select:
select st.id, st.name, st.no, st.gender, st.phone, st.id_card, st.is_college, st.address, st.degree, st.graduation_date, st.clazz_id, st.violation_count, st.violation_score, st.create_time, st.update_time, cz.id, cz.name as clazzName from student st left join clazz cz on st.clazz_id = cz.id
and st.name like concat('%',#{name},'%')
and degree =#{degree}
and clazz_id =#{clazzId}
order by create_time desc

mapper.update:
update student
name=#{name}, no=#{no}, phone=#{phone}, gender=#{gender}, degree=#{degree}, id_card=#{idCard}, is_college=#{isCollege}, address=#{address}, graduation_date=#{graduationDate}, violation_count=#{violationCount}, violation_score=#{violationScore}, clazz_id=#{clazzId},
where id = #{id}
